import {useState} from "react"
import API from "../services/api"
export default function ResumeAnalyzer()
{
    const [resume,setResume] = useState(null)
    const [jobDescription,setJobDescription] = useState("")
    const [result,setResult] = useState(null)
    const handleAnalyze = async() => {
        try{
            const formData = new FormData()
            formData.append("resume",resume)
            formData.append("jobDescription",jobDescription)
            const token= localStorage.getItem("token")
            console.log(token)
            const response = await API.post(
                "/resume/analyze",
                formData,
                {
                    headers: {
                        Authorization:`Bearer ${token}`,
                        "Content-Type":"multipart/form-data"
                    }
                }
            )
            setResult(response.data)
        } catch(error){
            console.log(error)
            alert("Analysis failed")
        }
        return (
    <div
        style={{
            minHeight: "100vh",
            background: "#f4f6f9",
            padding: "30px"
        }}
    >

        <div
            style={{
                maxWidth: "900px",
                margin: "auto",
                background: "white",
                padding: "30px",
                borderRadius: "15px",
                boxShadow: "0 4px 12px rgba(0,0,0,0.1)"
            }}
        >

            <h1
                style={{
                    textAlign: "center",
                    marginBottom: "30px"
                }}
            >
                ATS Resume Analyzer
            </h1>

            <input
                type="file"
                accept=".pdf"
                onChange={(e) =>
                    setResume(e.target.files[0])
                }
                style={{
                    marginBottom: "20px"
                }}
            />

            <textarea
                placeholder="Paste Job Description (Optional)"
                rows="6"
                value={jobDescription}
                onChange={(e) =>
                    setJobDescription(e.target.value)
                }
                style={{
                    width: "100%",
                    padding: "12px",
                    borderRadius: "8px",
                    marginBottom: "20px"
                }}
            />

            <button
                onClick={handleAnalyze}
                style={{
                    width: "100%",
                    padding: "12px",
                    background: "#2563eb",
                    color: "white",
                    border: "none",
                    borderRadius: "8px",
                    cursor: "pointer"
                }}
            >
                Analyze Resume
            </button>

            {result && (

                <div
                    style={{
                        marginTop: "30px"
                    }}
                >

                    <div
                        style={{
                            textAlign: "center",
                            background: "#eff6ff",
                            padding: "20px",
                            borderRadius: "12px"
                        }}
                    >

                        <h2>
                            ATS Score
                        </h2>

                        <h1
                            style={{
                                color: "#2563eb",
                                fontSize: "50px"
                            }}
                        >
                            {result.score}%
                        </h1>

                    </div>

                    <div
                        style={{
                            display: "grid",
                            gridTemplateColumns:
                                "1fr 1fr",
                            gap: "20px",
                            marginTop: "25px"
                        }}
                    >

                        <div>

                            <h3>
                                Matched Skills
                            </h3>

                            <ul>

                                {result.matchedSkills?.map(
                                    (skill, index) => (
                                        <li key={index}>
                                            ✅ {skill}
                                        </li>
                                    )
                                )}

                            </ul>

                        </div>

                        <div>

                            <h3>
                                Missing Keywords
                            </h3>

                            <ul>

                                {result.missingKeywords?.map(
                                    (skill, index) => (
                                        <li key={index}>
                                            ❌ {skill}
                                        </li>
                                    )
                                )}

                            </ul>

                        </div>

                    </div>

                    <div
                        style={{
                            marginTop: "25px"
                        }}
                    >

                        <h3>
                            Resume Sections
                        </h3>

                        <ul>

                            <li>
                                {result.sections?.education
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                Education
                            </li>

                            <li>
                                {result.sections?.projects
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                Projects
                            </li>

                            <li>
                                {result.sections?.skills
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                Skills
                            </li>

                            <li>
                                {result.sections?.certifications
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                Certifications
                            </li>

                            <li>
                                {result.sections?.github
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                GitHub
                            </li>

                            <li>
                                {result.sections?.linkedin
                                    ? "✅"
                                    : "❌"}
                                {" "}
                                LinkedIn
                            </li>

                        </ul>

                    </div>

                    <div
                        style={{
                            marginTop: "25px"
                        }}
                    >

                        <h3>
                            Suggestions
                        </h3>

                        <ul>

                            {result.suggestions?.map(
                                (item, index) => (
                                    <li key={index}>
                                        💡 {item}
                                    </li>
                                )
                            )}

                        </ul>

                    </div>

                </div>

            )}

        </div> 
    </div>
    )
}
}
